// Generic class
class Box<T> {
  private T value;
  public void set(T v) { value = v; }
  public T get() { return value; }
}

// Use it: type-safe, no casting
Box<String> b = new Box<>();
b.set("hello");
String s = b.get();          // no cast! compiler knows it's a String

// Compile ERROR (not runtime error): b.set(42);
// That's the whole point of generics.

// PRODUCER — you only READ from it
void printAll(List<? extends Number> list) {
  for (Number n : list) System.out.println(n);
  // list.add(42);  ← compile ERROR — can't add, only read
}

// CONSUMER — you only WRITE to it
void addNumbers(List<? super Integer> list) {
  list.add(42);
  list.add(100);
  // Number n = list.get(0);   ← unsafe — could be Object!
}

// The rule:
//   ? extends T  → you can read T, can't add (except null)
//   ? super T    → you can add T, can read only as Object

// At compile time:
List<String> a = new ArrayList<String>();
List<Integer> b = new ArrayList<Integer>();

// At runtime (after erasure), both look like:
List a = new ArrayList();
List b = new ArrayList();

// Consequences:

// 1. Can't check runtime type of generic parameter
if (a instanceof List<String>) { }        // compile error
if (a instanceof List<?>) { }              // OK — but only checks it's some List

// 2. Can't `new T()` — the type isn't known at runtime
class Cache<T> {
  T create() { return new T(); }           // compile error
  T create(Class<T> cls) throws Exception {
    return cls.getDeclaredConstructor().newInstance();   // workaround
  }
}

// 3. Overloads that differ only in generic parameter clash
void print(List<String> a) { }
void print(List<Integer> a) { }             // compile error — after erasure both are `print(List)`

// 4. Generic arrays are not allowed
T[] arr = new T[10];                        // compile error
@SuppressWarnings("unchecked")
T[] arr = (T[]) new Object[10];             // workaround (unsafe)

// File: GenericsDemo.java
// Run: javac GenericsDemo.java && java GenericsDemo
import java.util.*;
import java.util.function.*;

public class GenericsDemo {

  // Generic method with a Function parameter
  static <T, R> List<R> mapAll(List<T> in, Function<T, R> fn) {
    List<R> out = new ArrayList<>();
    for (T item : in) out.add(fn.apply(item));
    return out;
  }

  // Bounded generic — only Numbers
  static <T extends Number> double sum(List<T> nums) {
    double s = 0;
    for (T n : nums) s += n.doubleValue();
    return s;
  }

  // PECS example: copy from a producer to a consumer
  static <T> void copy(List<? extends T> from, List<? super T> to) {
    for (T item : from) to.add(item);
  }

  // Generic class with two type parameters
  static class Pair<A, B> {
    final A first;
    final B second;
    Pair(A a, B b) { first = a; second = b; }
    @Override public String toString() { return "(" + first + ", " + second + ")"; }
  }

  public static void main(String[] args) {
    // Generic method
    List<Integer> nums = List.of(1, 2, 3);
    List<String> asStr = mapAll(nums, n -> "num=" + n);
    System.out.println(asStr);              // [num=1, num=2, num=3]

    // Bounded generic — accepts Integer, Double, Long, but not String
    System.out.println(sum(List.of(1, 2, 3, 4)));      // 10.0
    System.out.println(sum(List.of(1.5, 2.5)));        // 4.0
    // sum(List.of("a", "b"));                        // compile error!

    // PECS in action: read from Integers (producer), write to Numbers (consumer)
    List<Integer> ints = new ArrayList<>(List.of(1, 2, 3));
    List<Number> allNums = new ArrayList<>();
    copy(ints, allNums);
    System.out.println(allNums);           // [1, 2, 3]

    // Generic class
    Pair<String, Integer> p = new Pair<>("score", 95);
    System.out.println(p);                 // (score, 95)

    // Erasure demonstrated:
    List<String> a = new ArrayList<>();
    List<Integer> b = new ArrayList<>();
    System.out.println(a.getClass() == b.getClass());   // true! same class at runtime
  }
}
